main_set = set()
for i in range(len(links)):
    links[i] = set(map(lambda x: (urllib.parse.unquote_plus(x).split("/")[-1]).replace("_", " "), links[i]))
    main_set.update(links[i])

dictionary = []  
with open("dict.txt", "r", encoding="utf-8") as f:
    dictionary = f.read().split()

stats = [0, 0, 0, 0]

for a in dictionary:
    i = 0
    while 1:
        if i >= 4:
            break
        if a in links[i]:
            print(a, i)
            stats[i] += 1
        i += 1

print(stats)

plt.bar([0, 1, 2, 3], stats)
plt.xlabel("Количество рукопожатий")
plt.ylabel("Попадания в слова из биологического словаря")#https://licey.net/free/6-biologiya/25-slovar_biologicheskih_terminov.html
